// Expect the sheet to have at least the following columns (case-insensitive):
//   phone (or e164 / mobile), first_name, last_name (or name), email
// Any other column is forwarded as metadata.raw.
function k(s) { return String(s || '').toLowerCase().trim().replace(/[^a-z0-9]+/g, '_'); }
const row = $input.first().json || {};
const flat = {};
for (const key of Object.keys(row)) flat[k(key)] = row[key];

const phone = (flat.phone || flat.e164 || flat.mobile || flat.phone_number || '').toString().trim();
const first = (flat.first_name || flat.firstname || '').toString().trim();
const last  = (flat.last_name  || flat.lastname  || '').toString().trim();
const name  = (flat.name || flat.full_name || [first, last].filter(Boolean).join(' ')).toString().trim();
const email = (flat.email || '').toString().trim();

return [{
  json: {
    e164: phone,
    first_name: first,
    last_name: last,
    name,
    email,
    raw: flat,
  },
}];

